/**
 * Returns the base TypeScript type for a field, without list or nullability wrappers.
 * Enum and object (relation) fields use the Prisma type name directly.
 */
function baseType(field: DMMF.Field): string {
  if (field.kind === 'enum' || field.kind === 'object') return field.type
  if (field.kind === 'unsupported') return 'unknown'
  return scalarToTs(field.type)
}

/**
 * Returns the full TypeScript type for a field, including list and nullability wrappers.
 *
 * - List fields become `T[]`
 * - Non-required, non-list fields become `T | null`
 */
export function prismaTypeToTs(field: DMMF.Field): string {
  const bt = baseType(field)
  if (field.isList) return `${bt}[]`
  if (!field.isRequired) return `${bt} | null`
  return bt
}

/**
 * Returns the subset of a model's fields suitable for a flat REST representation —
 * relation fields (`kind === 'object'`) and unsupported fields are excluded.
 */
function restFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind !== 'object' && f.kind !== 'unsupported')
}

/**
 * Identifies the best field to use as the URL path segment for resource identity.
 * Prefers the first `@id` field, then falls back to the first `@unique` field.
 */
function primaryField(model: DMMF.Model): DMMF.Field | undefined {
  return model.fields.find((f) => f.isId) ?? model.fields.find((f) => f.isUnique)
}

/** Derives the REST resource path from a model name, e.g. `"User"` → `"users"`. */
function toResourcePath(modelName: string): string {
  return modelName.toLowerCase() + 's'
}

/**
 * Generates a TypeScript interface representing a model record (flat, non-relation fields only).
 */
export function generateModelInterface(model: DMMF.Model): string {
  const lines = restFields(model).map((f) => `  ${f.name}: ${prismaTypeToTs(f)}`)
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Generates a TypeScript interface for the unique-identifier inputs used in
 * `findUnique`, `update`, and `delete` operations. All fields are optional
 * because callers supply exactly one of the available unique identifiers.
 */
export function generateWhereUniqueInput(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => f.isId || f.isUnique)
  const lines = uniqueFields.map((f) => `  ${f.name}?: ${baseType(f)}`)
  return `export interface ${model.name}WhereUniqueInput {\n${lines.join('\n')}\n}`
}

/**
 * Generates a TypeScript interface for the data payload used in `create` operations.
 * Auto-managed fields (read-only, auto-generated IDs) are made optional; all others
 * follow their schema nullability.
 */
export function generateCreateInput(model: DMMF.Model): string {
  const fields = restFields(model).filter((f) => !f.isReadOnly)
  const lines = fields.map((f) => {
    const isOptional = f.hasDefaultValue || (f.isId && f.hasDefaultValue) || (!f.isRequired && !f.isList)
    const bt = baseType(f)
    const tsType = f.isList ? `${bt}[]` : !f.isRequired ? `${bt} | null` : bt
    const marker = isOptional || (f.isId && f.hasDefaultValue) ? '?' : ''
    return `  ${f.name}${marker}: ${tsType}`
  })
  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}

/**
 * Generates a TypeScript interface for the data payload used in `update` operations.
 * All fields are optional (only the specified fields are updated).
 * Read-only and `@id` fields are excluded.
 */
export function generateUpdateInput(model: DMMF.Model): string {
  const fields = restFields(model).filter((f) => !f.isReadOnly && !f.isId)
  const lines = fields.map((f) => {
    const bt = baseType(f)
    const tsType = f.isList ? `${bt}[]` : !f.isRequired ? `${bt} | null` : bt
    return `  ${f.name}?: ${tsType}`
  })
  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}

/**
 * Generates a typed client class for a model with five CRUD methods:
 * `findMany`, `findUnique`, `create`, `update`, and `delete`.
 *
 * Each method issues a `fetch` call against a conventional REST endpoint derived
 * from the model name (e.g. `User` → `/users`).
 */
export function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const resource = toResourcePath(name)
  const idF = primaryField(model)
  const idFieldName = idF?.name ?? 'id'

  return `export class ${name}Client {
  #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }

  async findMany(params?: {
    where?: Partial<${name}>
    skip?: number
    take?: number
  }): Promise<${name}[]> {
    const url = new URL(this.#baseUrl + '/${resource}')
    if (params?.skip !== undefined) url.searchParams.set('skip', String(params.skip))
    if (params?.take !== undefined) url.searchParams.set('take', String(params.take))
    if (params?.where !== undefined) url.searchParams.set('where', JSON.stringify(params.where))
    const response = await fetch(url.toString())
    if (!response.ok) throw new Error('HTTP ' + response.status + ': ' + await response.text())
    return response.json() as Promise<${name}[]>
  }

  async findUnique(params: { where: ${name}WhereUniqueInput }): Promise<${name} | null> {
    const id = params.where.${idFieldName}
    const response = await fetch(this.#baseUrl + '/${resource}/' + encodeURIComponent(String(id)))
    if (response.status === 404) return null
    if (!response.ok) throw new Error('HTTP ' + response.status + ': ' + await response.text())
    return response.json() as Promise<${name}>
  }

  async create(params: { data: ${name}CreateInput }): Promise<${name}> {
    const response = await fetch(this.#baseUrl + '/${resource}', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!response.ok) throw new Error('HTTP ' + response.status + ': ' + await response.text())
    return response.json() as Promise<${name}>
  }

  async update(params: { where: ${name}WhereUniqueInput; data: ${name}UpdateInput }): Promise<${name}> {
    const id = params.where.${idFieldName}
    const response = await fetch(this.#baseUrl + '/${resource}/' + encodeURIComponent(String(id)), {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!response.ok) throw new Error('HTTP ' + response.status + ': ' + await response.text())
    return response.json() as Promise<${name}>
  }

  async delete(params: { where: ${name}WhereUniqueInput }): Promise<${name}> {
    const id = params.where.${idFieldName}
    const response = await fetch(this.#baseUrl + '/${resource}/' + encodeURIComponent(String(id)), {
      method: 'DELETE',
    })
    if (!response.ok) throw new Error('HTTP ' + response.status + ': ' + await response.text())
    return response.json() as Promise<${name}>
  }
}`
}

/**
 * Assembles the full `rest-client.ts` file content from all models in the schema.
 * Emits one interface block and one client class per model, separated by blank lines.
 */
export function generateRestClientFile(models: readonly DMMF.Model[]): string {
  const header = '// Auto-generated by @prisma/generator-rest-client — do not edit manually\n'

  const blocks = models.flatMap((model) => [
    generateModelInterface(model),
    generateWhereUniqueInput(model),
    generateCreateInput(model),
    generateUpdateInput(model),
    generateModelClient(model),
  ])

  return header + '\n' + blocks.join('\n\n') + '\n'
}

