import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import { generateRestClientFile } from './template'

/**
 * Main generation entry point. Reads model metadata from the DMMF, generates
 * a typed REST client, and writes `rest-client.ts` to the configured output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error(
      'output path is required in the generator block. ' +
        'Add `output = "./generated/rest-client"` to your generator config in schema.prisma.',
    )
  }

  await fs.mkdir(outputDir, { recursive: true })

  const { models } = options.dmmf.datamodel
  const content = generateRestClientFile(models)

  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}

import { build } from '../../../helpers/compile/build'
import { adapterConfig } from '../../../helpers/compile/configs'

// The shebang banner is required on the CJS bundle so the OS can execute
// `dist/index.js` directly when Prisma CLI spawns it as `prisma-generator-rest-client`.
void build(adapterConfig.map((config) => (config.format === 'cjs' ? { ...config, banner: { js: '#!/usr/bin/env node' } } : config)))
